  switch (item.itemType) {
    case 'collection':
      return item.riskSeverity === 'severe' ? 'pay_for_delete' : 'dispute';
    case 'charge_off':
      return 'dispute';
    case 'late_payment':
      return 'goodwill_letter';
    case 'bankruptcy':
    case 'foreclosure':
      return 'wait';
